import React, { useState, useEffect, useCallback } from 'react';
import TableTemplate from '../components/TableTemplate';
import FormTemplate from '../components/FormTemplate';
import SearchComponent from '../components/SearchComponent';
import { userService } from '../api/userService'; // ONLY CHANGE HERE

function UserPage() {
  const service = userService;

  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [isEditing, setIsEditing] = useState(false);
  const [currentEntity, setCurrentEntity] = useState(service.initialFormState);
  const [currentId, setCurrentId] = useState(null);
  const [vehicles, setVehicles] = useState([]);

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const records = await service.getAll();
      setData(records);

      // Also fetch vehicles for validation
      const vehicleResponse = await fetch('http://localhost:3000/vehicle');
      const vehicleData = await vehicleResponse.json();
      setVehicles(vehicleData);
    } catch (err) {
      setError(`Failed to fetch ${service.name} data.`);
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, [service]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleSave = async (formData, isEditMode, id) => {
    try {
      // Validate Vehicle_ID field
      if (formData.Vehicle_ID && formData.Vehicle_ID !== '') {
        if (vehicles.length > 0) {
          const vehicleExists = vehicles.some(vehicle => 
            vehicle.Vehicle_ID === parseInt(formData.Vehicle_ID)
          );

          if (!vehicleExists) {
            setError(`Vehicle ID ${formData.Vehicle_ID} does not exist. Please enter a valid Vehicle ID or leave empty. Available IDs: ${vehicles.map(v => v.Vehicle_ID).join(', ')}`);
            return;
          }
        }
      }

      setError(null);

      if (isEditMode) {
        await service.update(id, formData);
      } else {
        await service.add(formData); 
      }
      fetchData(); 
      handleCancelEdit();
    } catch (err) {
      let errorMessage = `Failed to ${isEditMode ? 'update' : 'add'} ${service.name} record.`;

      if (err.response?.data?.message) {
        if (err.response.data.message.includes('foreign key constraint')) {
          errorMessage = `Invalid Vehicle ID. The Vehicle_ID field must reference an existing Vehicle ID or be empty.`;
        } else {
          errorMessage = err.response.data.message;
        }
      } else if (err.message) {
        errorMessage = err.message;
      }

      setError(errorMessage);
      console.error(err);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm(`Are you sure you want to delete ${service.name} ID ${id}?`)) return;
    try {
      await service.remove(id);
      fetchData();
    } catch (err) {
      setError(`Failed to delete ${service.name} record. Check for dependent records.`);
      console.error(err);
    }
  };

  const handleEdit = (item) => {
    setIsEditing(true);

    let itemData = { ...item };
    if (itemData.Installation_Date) {
      itemData.Installation_Date = new Date(itemData.Installation_Date).toISOString().split('T')[0];
    }

    setCurrentEntity(itemData);
    setCurrentId(item[service.entityIdKey]);
  };

  const handleCancelEdit = () => {
      setIsEditing(false);
      setCurrentEntity(service.initialFormState);
      setCurrentId(null);
  };

  // 🌿 Updated style to match Bin/Driver pages
  const pageStyles = {
    background: 'rgba(255, 255, 255, 0.95)',
    backdropFilter: 'blur(20px)',
    borderRadius: '24px',
    padding: '40px',
    margin: '20px 0',
    boxShadow: '0 20px 60px rgba(40,167,69,0.2), 0 10px 30px rgba(40,167,69,0.1)',
    border: '2px solid rgba(40,167,69,0.3)',
    position: 'relative',
    overflow: 'hidden',
  };

  const headerStyles = {
    textAlign: 'center',
    background: 'linear-gradient(135deg, #a8e063 0%, #56ab2f 100%)',
    WebkitBackgroundClip: 'text',
    WebkitTextFillColor: 'transparent',
    backgroundClip: 'text',
    fontSize: '3rem',
    fontWeight: '800',
    marginBottom: '30px',
    borderBottom: '4px solid transparent',
    borderImage: 'linear-gradient(90deg, #a8e063, #56ab2f) 1',
    paddingBottom: '20px',
    letterSpacing: '0.5px',
  };

  const errorStyles = {
    background: 'linear-gradient(135deg, #f8d7da, #f5c6cb)',
    color: '#721c24',
    padding: '15px 20px',
    borderRadius: '12px',
    marginBottom: '25px',
    border: '1px solid #f5c6cb',
    fontSize: '1rem',
    fontWeight: '600',
  };

  const loadingStyles = {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    height: '300px',
    fontSize: '1.5rem',
    color: '#28a745',
    fontWeight: '600',
  };

  if (loading)
    return (
      <div style={pageStyles}>
        <div style={loadingStyles}>
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '2.5rem', marginBottom: '10px' }}>⏳</div>
            Loading {service.name} data...
          </div>
        </div>
      </div>
    );

  return (
    <div style={pageStyles}>
      <div style={headerStyles}>
        <div style={{ fontSize: '4rem', marginBottom: '10px' }}>👤</div>
        <h2
          style={{
            margin: 0,
            fontSize: '3.2rem',
            fontWeight: '800',
            letterSpacing: '0.5px',
          }}
        >
          {service.name}
        </h2>
        <p
          style={{
            margin: '12px 0 0 0',
            fontSize: '1rem',
            color: '#28a745',
            opacity: 0.85,
            fontWeight: '500',
          }}
        >
          Manage user profiles and linked vehicles efficiently
        </p>
      </div>

      {error && <div style={errorStyles}>⚠️ Error: {error}</div>}

      <SearchComponent 
          entityName={service.name} 
          entityIdKey={service.entityIdKey}
          onSearch={service.getOne} 
          onEdit={handleEdit}
          onDelete={handleDelete}
      />

      <FormTemplate
        fields={service.fields}
        initialData={currentEntity}
        onSave={handleSave}
        isEditing={isEditing}
        entityId={currentId}
        onCancelEdit={handleCancelEdit}
      />

      <h3
        style={{
          fontSize: '1.8rem',
          fontWeight: '700',
          textAlign: 'center',
          marginTop: '30px',
          marginBottom: '25px',
          background: 'linear-gradient(135deg, #a8e063 0%, #56ab2f 100%)',
          WebkitBackgroundClip: 'text',
          WebkitTextFillColor: 'transparent',
        }}
      >
        📋 All {service.name} Records
      </h3>

      <TableTemplate
        data={data}
        columns={service.columns}
        entityIdKey={service.entityIdKey}
        onEdit={handleEdit}
        onDelete={handleDelete}
      />
    </div>
  );
}

export default UserPage;
